mapper.insert:
		/*
             SQL ID : SrvyVwitmDAO.srvyVwitmBulkRegist
             설  명 : 설문보기항목일괄등록
         */
         INSERT ALL

			INTO TB_LMS_SRVY_VWITM (
	         	  SRVY_VWITM_ID
				, SRVY_QSTN_ID
				, VWITM_GBNCD
				, VWITM_CTS
				, VWITM_SEQNO
				, MVMN_SRVY_QSTN_ID
				, ETC_INPTYN
				, RGTR_ID
				, REG_DTTM
	         ) VALUES (
	         	  #{item.srvyVwitmId}
				, #{item.srvyQstnId}
				, #{item.vwitmGbncd}
				, #{item.vwitmCts}
				, #{item.vwitmSeqno}
				, #{item.mvmnSrvyQstnId}
				, #{item.etcInptyn}
				, #{item.rgtrId}
				, FN_DTTM()
	         )

		SELECT * FROM DUAL

mapper.delete:
		/*
             SQL ID : SrvyVwitmDAO.srvyVwitmDelete
             설  명 : 설문보기항목삭제
         */
        DELETE FROM TB_LMS_SRVY_VWITM
         WHERE SRVY_QSTN_ID = #{srvyQstnId}

mapper.insert:
/* SQL ID : SrvyVwitmDAO.srvyVwitmCopy 설 명 : 설문보기항목가져오기 */ INSERT INTO TB_LMS_SRVY_VWITM ( SRVY_VWITM_ID , SRVY_QSTN_ID , VWITM_GBNCD , VWITM_CTS , VWITM_SEQNO , ETC_INPTYN , RGTR_ID , REG_DTTM ) SELECT 'SRVW0' || TO_CHAR(SYSDATE, 'YYMMDDHH24MISS') || LPAD(MOD(EXTRACT(SECOND FROM SYSTIMESTAMP) * 1000, 1000), 3, '0') || LOWER(SUBSTR(RAWTOHEX(SYS_GUID()), 1, 7)) || LPAD(ROW_NUMBER() OVER(ORDER BY NULL), 3, '0') AS SRVY_VWITM_ID , A.* FROM (
SELECT #{item.srvyQstnId} AS SRVY_QSTN_ID , Q.VWITM_GBNCD , Q.VWITM_CTS , Q.VWITM_SEQNO , Q.ETC_INPTYN , #{item.rgtrId} AS RGTR_ID , FN_DTTM() AS REG_DTTM FROM DUAL LEFT JOIN TB_LMS_SRVY_VWITM Q ON Q.SRVY_QSTN_ID = #{item.copySrvyQstnId} WHERE Q.SRVY_QSTN_ID IS NOT NULL
) A

mapper.select:
/* SQL ID : SrvyVwitmDAO.srvyVwitmBulkList 설 명 : 설문보기항목일괄조회 */ SELECT VWITM.* FROM TB_LMS_SRVYPPR SRVYPPR JOIN TB_LMS_SRVY_QSTN QSTN ON SRVYPPR.SRVYPPR_ID = QSTN.SRVYPPR_ID AND QSTN.DELYN = 'N' JOIN TB_LMS_SRVY_VWITM VWITM ON QSTN.SRVY_QSTN_ID = VWITM.SRVY_QSTN_ID WHERE 1 = 1
AND QSTN.QSTN_RSPNS_TYCD = #{qstnRspnsTycd}
AND SRVYPPR.SRVY_ID IN (SELECT SRVY_ID FROM TB_LMS_SRVY WHERE DELYN = 'N' AND USEYN = 'Y' AND (SRVY_ID = #{srvyId} OR UP_SRVY_ID = #{srvyId})) ORDER BY SRVYPPR.SRVY_ID, SRVYPPR.SRVY_SEQNO, QSTN.QSTN_SEQNO, VWITM.VWITM_SEQNO
AND SRVYPPR.SRVY_ID = #{srvyId} ORDER BY SRVYPPR.SRVY_SEQNO, QSTN.QSTN_SEQNO, VWITM.VWITM_SEQNO
